import Prism from 'prismjs'
import type { Grammar } from 'prismjs'

// Prism 组件文件依赖全局 Prism 对象来注册语法
if (typeof globalThis !== 'undefined' && !(globalThis as Record<string, unknown>).Prism) {
    (globalThis as Record<string, unknown>).Prism = Prism
}

const languageLoaders: Record<string, () => Promise<unknown>> = {
    markup: () => import('prismjs/components/prism-markup'),
    html: () => import('prismjs/components/prism-markup'),
    xml: () => import('prismjs/components/prism-markup'),
    svg: () => import('prismjs/components/prism-markup'),
    css: () => import('prismjs/components/prism-css'),
    clike: () => import('prismjs/components/prism-clike'),
    javascript: () => import('prismjs/components/prism-javascript'),
    js: () => import('prismjs/components/prism-javascript'),
    typescript: () => import('prismjs/components/prism-typescript'),
    ts: () => import('prismjs/components/prism-typescript'),
    jsx: () => import('prismjs/components/prism-jsx'),
    tsx: () => import('prismjs/components/prism-tsx'),
    json: () => import('prismjs/components/prism-json'),
    bash: () => import('prismjs/components/prism-bash'),
    sh: () => import('prismjs/components/prism-bash'),
    python: () => import('prismjs/components/prism-python'),
    py: () => import('prismjs/components/prism-python'),
    sql: () => import('prismjs/components/prism-sql'),
    java: () => import('prismjs/components/prism-java'),
    c: () => import('prismjs/components/prism-c'),
    cpp: () => import('prismjs/components/prism-cpp'),
    go: () => import('prismjs/components/prism-go'),
    rust: () => import('prismjs/components/prism-rust'),
    scss: () => import('prismjs/components/prism-scss'),
    yaml: () => import('prismjs/components/prism-yaml'),
    yml: () => import('prismjs/components/prism-yaml'),
    markdown: () => import('prismjs/components/prism-markdown'),
    md: () => import('prismjs/components/prism-markdown'),
    shell: () => import('prismjs/components/prism-shell-session'),
}

const loadedLanguages = new Set<string>()

export async function loadLanguage(lang: string): Promise<string> {
    if (lang === 'plaintext') return 'plaintext'

    if (loadedLanguages.has(lang)) return lang

    const loader = languageLoaders[lang]
    if (!loader) return 'plaintext'

    try {
        await loader()
        loadedLanguages.add(lang)
        return lang
    } catch {
        return 'plaintext'
    }
}

export function isLanguageLoaded(lang: string): boolean {
    return lang === 'plaintext' || loadedLanguages.has(lang)
}

export function getGrammar(lang: string): Grammar | undefined {
    if (lang === 'plaintext') return undefined
    return Prism.languages[lang] as Grammar | undefined
}

export { Prism }

/**
 * BrutxUI Prism Theme — Neo-Brutalist Syntax Highlighting
 *
 * 使用专用 --brutal-code-* 变量控制 token 颜色，
 * 与 --brutal-primary 等设计令牌解耦，确保所有主题下对比度达标。
 * 消费者可通过覆盖 --brutal-code-* 变量自定义高亮配色。
 */

code[class*="language-"],
pre[class*="language-"] {
    color: var(--brutal-code-foreground, var(--brutal-fg));
    font-family: ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace;
    line-height: 1.7;
    white-space: pre;
    word-spacing: normal;
    word-break: normal;
    word-wrap: normal;
    tab-size: 4;
    hyphens: none;
}

/* --- Token 颜色映射 --- */
/* 所有颜色均通过 --brutal-code-* 变量，默认值确保 WCAG AA 对比度 >= 4.5:1 */

.token.comment,
.token.prolog,
.token.doctype,
.token.cdata {
    color: var(--brutal-code-comment, #6b7280);
    font-style: italic;
}

.token.punctuation {
    color: var(--brutal-code-punctuation, #4b5563);
}

.token.property,
.token.tag,
.token.boolean,
.token.number,
.token.constant,
.token.symbol,
.token.deleted {
    color: var(--brutal-code-number, #c0392b);
}

.token.selector,
.token.attr-name,
.token.string,
.token.char,
.token.builtin,
.token.inserted {
    color: var(--brutal-code-string, #2e7d32);
}

.token.operator,
.token.entity,
.token.url {
    color: var(--brutal-code-operator, #1565c0);
}

.token.atrule,
.token.attr-value,
.token.keyword {
    color: var(--brutal-code-keyword, #00838f);
}

.token.function,
.token.class-name {
    color: var(--brutal-code-function, #c62828);
}

.token.regex,
.token.important,
.token.variable {
    color: var(--brutal-code-variable, #9c27b0);
}

/* --- 暗色模式覆盖 --- */

.dark {
    --brutal-code-comment: #9ca3af;
    --brutal-code-punctuation: #d1d5db;
    --brutal-code-number: #ef5350;
    --brutal-code-string: #66bb6a;
    --brutal-code-operator: #42a5f5;
    --brutal-code-keyword: #26c6da;
    --brutal-code-function: #ff7043;
    --brutal-code-variable: #ce93d8;
}

/* --- 行号样式（Prism 插件兼容） --- */

.line-numbers .line-numbers-rows {
    border-right: var(--brutal-border-width, 3px) solid var(--brutal-border-color);
    padding-right: 1rem;
    margin-right: 1rem;
}

.line-numbers-rows > span::before {
    color: var(--brutal-fg);
    opacity: 0.3;
}

/* --- 高亮行（Prism line-highlight 插件兼容） --- */

.line-highlight {
    background: var(--brutal-accent);
    opacity: 0.15;
}
